import React, { Component } from 'react'
import './App.css';
import NAV from '../Nav/nav'
import MAIN from '../Main/Main'
import CREATEWIND from '../CreatePostWindow/CreatePostWindow'
import POSTWINDOW from '../PostWindow/PostWindow'
// import Post from '../../Post'
import {
  BrowserRouter as Router,
  Routes,
  Route,
} from 'react-router-dom';

import { getNews } from '../db.js'

export default class App extends Component {


  constructor(props) {
    super(props)

    this.state = {
      listVisible: "",
      idPost: 0
    }
  }
  render() {
    const Post = {
      0: {
        tags: "бюст, череп, золото",
        title: "Статуя",
        author: "Krisma_OFF",
        text: "Lorem ipsum, dolor sit amet consectetur adipisicing elit. Dolor quis quas aperiam repellat nemo autem quisquam eos! Quo, libero corrupti!",
        img: "https://clck.ru/YpZ2T",
        link: "https://clck.ru/YpZ2T",
        id: 0
      },
    }
    const PostTwo = [
      {
        tags: "бюст, череп, золото",
        title: "Статуя",
        author: "Krisma_OFF",
        text: "Lorem ipsum, dolor sit amet consectetur adipisicing elit. Dolor quis quas aperiam repellat nemo autem quisquam eos! Quo, libero corrupti!",
        img: "https://clck.ru/YpZ2T",
        link: "https://clck.ru/YpZ2T",
        id: 0
      },
    ]
    const search = (e) => {
      this.setState({ listVisible: e })
    }
    const saveData = (e) => {
      getNews(e)
      console.log(e, "saveData - APP");
    }
    const openWindPots = (id) => {
      this.setState({ idPost: id })
    }
    const { listVisible, idPost } = this.state
    return (
      <div>
        <Router>
          <button onClick={()=>{
            console.log(Post)
          }}>fff</button>
          <NAV search={search} />
          <div className="empty-block"></div>

          {Post[0].title}
          {PostTwo[0].title}
          <Routes>
            <Route
              exact path="/"
              element={<MAIN listVisible={listVisible} tag={null} list={Post} openWindPots={openWindPots} />}
            />
            <Route
              path="/posts/:id_post"
              // element={<POSTWINDOW listVisible={listVisible} list={Post} listId={Post[idPost]} openWindPots={openWindPots}/>}
              element={<POSTWINDOW list={Post} openWindPots={openWindPots} />}
            />
            <Route
              path="/create-post"
              element={<CREATEWIND saveData={saveData} />}
            />
            <Route
              path="*"
              element={<h1 className="error">ERROR404</h1>}
            />

          </Routes>

        </Router>
      </div>
    )
  }
}
